import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { designCode, beadCount } = body;

    if (!designCode || !beadCount) {
      return NextResponse.json(
        { error: "designCode and beadCount are required" },
        { status: 400 }
      );
    }

    const order = await prisma.order.create({
      data: {
        designCode,
        designState: JSON.stringify({ designCode, beadCount }),
        status: "new",
        beadCount: Number(beadCount),
      },
    });

    return NextResponse.json(order, { status: 201 });
  } catch (error) {
    console.error("Failed to create order:", error);
    return NextResponse.json(
      { error: "Failed to create order" },
      { status: 500 }
    );
  }
}

export async function GET() {
  try {
    const orders = await prisma.order.findMany({
      orderBy: { createdAt: "desc" },
    });

    return NextResponse.json(orders);
  } catch (error) {
    console.error("Failed to fetch orders:", error);
    return NextResponse.json(
      { error: "Failed to fetch orders" },
      { status: 500 }
    );
  }
}

"use client";

import { usePathname, useRouter } from "next/navigation";
import { useState } from "react";

const NAV_LINKS = [
  { href: "/admin/templates", label: "Шаблоны" },
  { href: "/admin/orders", label: "Заказы" },
  { href: "/admin/beads", label: "Бусины" },
];

export default function AdminLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const pathname = usePathname();
  const router = useRouter();
  const [loggingOut, setLoggingOut] = useState(false);

  const isLoginPage = pathname === "/admin/login";

  const handleLogout = async () => {
    setLoggingOut(true);
    try {
      await fetch("/api/admin/auth", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "logout" }),
      });
    } catch {
      // Even if the request fails, redirect to login
    } finally {
      router.push("/admin/login");
    }
  };

  if (isLoginPage) {
    return <>{children}</>;
  }

  return (
    <div className="flex h-screen">
      {/* Sidebar */}
      <aside className="w-56 bg-gray-100 border-r border-gray-200 flex flex-col shrink-0">
        <div className="p-4 border-b border-gray-200">
          <h1 className="text-lg font-bold text-gray-900">
            Bead Designer Admin
          </h1>
        </div>
        <nav className="flex-1 p-2">
          {NAV_LINKS.map((link) => {
            const isActive =
              pathname === link.href || pathname.startsWith(link.href + "/");
            return (
              <a
                key={link.href}
                href={link.href}
                className={`block px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                  isActive
                    ? "bg-blue-100 text-blue-900"
                    : "text-gray-700 hover:bg-gray-200"
                }`}
              >
                {link.label}
              </a>
            );
          })}
        </nav>
        <div className="p-2 border-t border-gray-200">
          <button
            onClick={handleLogout}
            disabled={loggingOut}
            className="w-full px-3 py-2 text-sm font-medium text-gray-700 hover:bg-gray-200 rounded-md transition-colors disabled:opacity-50"
          >
            {loggingOut ? "Выход..." : "Выйти"}
          </button>
        </div>
      </aside>

      {/* Main content */}
      <main className="flex-1 admin-root overflow-auto p-6">
        {children}
      </main>
    </div>
  );
}

// This is a Prisma schema file.
// Learn more: https://pris.ly/d/prisma-schema

datasource db {
  provider = "sqlite"
}

generator client {
  provider = "prisma-client-js"
}

model Bead {
  id        Int      @id @default(autoincrement())
  name      String
  nameRu    String
  shape     String   // "sphere" | "disc" | "star" | "heart" | "cylinder" — mapped in app
  size      Float
  material  String   // "wood" | "silicone" | "knit" | "plastic" — mapped in app
  color     String
  createdAt DateTime @default(now())
}

model Template {
  id              Int      @id @default(autoincrement())
  name            String
  designCode      String   @unique
  beadCount       Int
  isApproved      Boolean  @default(true)
  isUserSubmitted Boolean  @default(false)
  createdAt       DateTime @default(now())
}

model Order {
  id          Int      @id @default(autoincrement())
  designCode  String   @unique
  designState String   // JSON string of SerializableDesign
  status      String   @default("new")  // "new" | "processing" | "completed"
  beadCount   Int
  createdAt   DateTime @default(now())
}

import { NextRequest, NextResponse } from "next/server";

export function proxy(request: NextRequest) {
  const { pathname } = request.nextUrl;
  const token = request.cookies.get("admin_token")?.value;

  // Whitelist the login page and auth API — no auth check needed
  if (pathname === "/admin/login" || pathname === "/api/admin/auth") {
    return NextResponse.next();
  }

  // Guard /admin/* page routes and /api/admin/* API routes
  if (pathname.startsWith("/admin") || pathname.startsWith("/api/admin")) {
    if (!token) {
      // Page routes: redirect to login
      if (pathname.startsWith("/admin")) {
        const loginUrl = request.nextUrl.clone();
        loginUrl.pathname = "/admin/login";
        return NextResponse.redirect(loginUrl);
      }
      // API routes: return 401 JSON
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }
  }

  return NextResponse.next();
}

export const config = {
  matcher: ["/admin/:path*", "/api/admin/:path*"],
};

